import React from 'react';
import styles from './details.module.css';

const Details: React.FC = () => {
  return (
    <div className={styles.wrapper_details}>
        <p>
            <strong className={styles.bold}>Wax:</strong> Top grade Soy wax that delivers a smoke less,  consistent burn</p>
        <p>
            <strong className={styles.bold}>Fragrance:</strong> Premium quality ingredients with natural essential oils </p>
        <div>
            <span><strong className={styles.bold}>Burning Time:</strong> 70-75 hours</span>
            <span><strong className={styles.bold}>Dimension:</strong> 10cm x 5cm </span>
            <span>Weight: 400g </span>
        </div>

    </div>
  )
}

export default Details;
